// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class LmdbNativeTupleMetricsTest {

	// counters are JVM-global: earlier suite members publishing distinct-tracker rows must not leak in
	@BeforeEach
	@AfterEach
	void resetCounters() {
		PrimitiveTupleTable.PROBES.set(0L);
		PrimitiveTupleTable.INSERTIONS.set(0L);
		NativeDistinctTracker.PRIMITIVE_ROWS.set(0L);
		NativeDistinctTracker.OBJECT_ROWS.set(0L);
	}

	@Test
	void unownedPrimitiveTupleTableDoesNotPublishCounters() {
		PrimitiveTupleTable table = new PrimitiveTupleTable(2, 4);
		int[] slots = { 0, 1 };

		assertThat(table.findOrInsert(new long[] { 10L, 20L }, slots, false)).isZero();
		assertThat(table.findOrInsert(new long[] { 10L, 20L }, slots, false)).isZero();
		assertThat(table.find(new long[] { 30L, 40L }, slots, false)).isEqualTo(-1);

		assertThat(PrimitiveTupleTable.PROBES.get()).isZero();
		assertThat(PrimitiveTupleTable.INSERTIONS.get()).isZero();
	}

	@Test
	void distinctTrackerDoesNotPublishBeforeOwnershipBoundary() {
		NativeDistinctTracker tracker = new NativeDistinctTracker(new int[] { 0, 1 });

		assertThat(tracker.add(new long[] { 10L, 20L })).isTrue();
		assertThat(tracker.add(new long[] { 10L, 20L })).isFalse();

		assertThat(NativeDistinctTracker.PRIMITIVE_ROWS.get()).isZero();
		assertThat(NativeDistinctTracker.OBJECT_ROWS.get()).isZero();
	}
}
